def parse_roman(s):
    roman_map = {
        'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000
    }

    # Validate characters
    if not s:
        return -1

    valid_chars = set(roman_map.keys())
    for char in s:
        if char not in valid_chars:
            return -1

    # Check for invalid repetitions first
    i = 0
    while i < len(s):
        char = s[i]
        count = 1
        while i + count < len(s) and s[i + count] == char:
            count += 1

        if char in ['I', 'X', 'C', 'M']:
            if count > 3:
                return -1
        elif char in ['V', 'L', 'D']:
            if count > 1:
                return -1

        i += count

    # Calculate value
    total = 0
    prev_val = 0

    for i in range(len(s) - 1, -1, -1):
        curr_val = roman_map[s[i]]

        if curr_val < prev_val:
            total -= curr_val
        else:
            total += curr_val

        prev_val = curr_val

    # Check for invalid subtractive pairs in forward direction
    # Valid pairs are: IV, IX, XL, XC, CD, CM
    valid_pairs = {('I', 'V'), ('I', 'X'), ('X', 'L'), ('X', 'C'), ('C', 'D'), ('C', 'M')}

    for i in range(len(s) - 1):
        c1 = s[i]
        c2 = s[i+1]
        if roman_map[c1] < roman_map[c2]:
            if (c1, c2) not in valid_pairs:
                return -1

    return total
